using System.Windows.Forms;

public class MainForm : Form
{
    private StatusStrip statusStrip;

    public MainForm()
    {
        statusStrip = new StatusStrip();
        // .NET 9: StatusStrip no longer defaults to ToolStripRenderMode.System.
        // Set it explicitly to preserve the previous appearance.
        statusStrip.RenderMode = ToolStripRenderMode.System;
        Controls.Add(statusStrip);
    }
}

using System;
using System.Drawing.Design;
using System.Windows.Forms;
using System.Windows.Forms.Design;

public class MyPropertyEditor : UITypeEditor
{
    public override object? EditValue(
        System.ComponentModel.ITypeDescriptorContext? context,
        IServiceProvider provider,
        object? value)
    {
        var editorService = provider?.GetService(typeof(IWindowsFormsEditorService))
            as IWindowsFormsEditorService;
        if (editorService == null)
            return value;

        // .NET 9: IWindowsFormsEditorService.DropDownControl parameter is now
        // non-nullable. Guard against passing null to avoid ArgumentNullException.
        Control? dropDown = CreateDropDown(value);
        if (dropDown is not null)
        {
            editorService.DropDownControl(dropDown);
            value = GetValueFromDropDown(dropDown);
        }

        return value;
    }

    private Control? CreateDropDown(object? currentValue) => new ListBox();

    private object? GetValueFromDropDown(Control dropDown) =>
        (dropDown as ListBox)?.SelectedItem;

    public override UITypeEditorEditStyle GetEditStyle(
        System.ComponentModel.ITypeDescriptorContext? context) =>
        UITypeEditorEditStyle.DropDown;
}

